import java.io.*;
import java.nio.file.*;
import java.util.*;

public class DiskCache {
    private final Path cacheDir;

    public DiskCache(String directory) throws IOException {
        this.cacheDir = Paths.get(directory);
        Files.createDirectories(cacheDir);
    }

    public void put(String key, Object value) throws IOException {
        try (ObjectOutputStream oos = new ObjectOutputStream(Files.newOutputStream(getFilePath(key)))) {
            oos.writeObject(value);
        }
    }

    public <T> T get(String key, Class<T> clazz) throws IOException, ClassNotFoundException {
        Path filePath = getFilePath(key);
        if (!Files.exists(filePath)) {
            return null;
        }
        try (ObjectInputStream ois = new ObjectInputStream(Files.newInputStream(filePath))) {
            return clazz.cast(ois.readObject());
        }
    }

    public void remove(String key) throws IOException {
        Files.deleteIfExists(getFilePath(key));
    }

    private Path getFilePath(String key) {
        return cacheDir.resolve(key + ".cache");
    }

    public static void main(String[] args) {
        try {
            DiskCache cache = new DiskCache("cache");

            // Example object to store
            UserPreferences preferences = new UserPreferences();
            preferences.setTheme("dark");
            preferences.setFontSize(14);

            // Store in cache
            cache.put("userPrefs", preferences);

            // Retrieve from cache
            UserPreferences retrievedPreferences = cache.get("userPrefs", UserPreferences.class);
            if (retrievedPreferences != null) {
                System.out.println("Theme: " + retrievedPreferences.getTheme());
                System.out.println("Font Size: " + retrievedPreferences.getFontSize());
            }

            // Remove from cache
            cache.remove("userPrefs");

        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }
    }
}

class UserPreferences implements Serializable {
    private String theme;
    private int fontSize;

    public void setTheme(String theme) {
        this.theme = theme;
    }

    public String getTheme() {
        return theme;
    }

    public void setFontSize(int fontSize) {
        this.fontSize = fontSize;
    }

    public int getFontSize() {
        return fontSize;
    }
}